// reactapp/src/utils/api.js

import axios from "axios";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
  timeout: 20000,
});

api.interceptors.response.use(
  (res) => res,
  (err) => {
    const message =
      err.response?.data?.message ||
      err.response?.data ||
      err.message ||
      "Unknown error";
    return Promise.reject(new Error(message));
  }
);

// ---------------- AUTH ----------------
export const authRegister = (data) =>
  api.post("/api/auth/register", data).then((r) => r.data);

export const authLogin = (data) =>
  api.post("/api/auth/login", data).then((r) => r.data);

// ---------------- PATIENT / DOCTOR ----------------
export const fetchPatients = () =>
  api.get("/api/patients").then((r) => r.data);

export const createPatient = (data) =>
  api.post("/api/patients", data).then((r) => r.data);

export const fetchDoctors = () =>
  api.get("/api/doctors").then((r) => r.data);

// ---------------- APPOINTMENTS ----------------
export const createAppointment = (data) =>
  api.post("/api/appointments", data).then((r) => r.data);

export const setAppointmentStatus = (id, status) =>
  api.patch(`/api/appointments/${id}/status`, { status }).then((r) => r.data);

// Preferred: path-param endpoints
export const fetchAppointmentsByDoctor = (doctorId) =>
  api.get(`/api/appointments/doctor/${doctorId}`).then((r) => r.data);

export const fetchAppointmentsByPatient = (patientId) =>
  api.get(`/api/appointments/patient/${patientId}`).then((r) => r.data);

// Optional: query versions
export const fetchAppointmentsByDoctorQuery = (doctorId) =>
  api
    .get(`/api/appointments/doctor`, { params: { doctorId } })
    .then((r) => r.data);

export const fetchAppointmentsByPatientQuery = (patientId) =>
  api
    .get(`/api/appointments/patient`, { params: { patientId } })
    .then((r) => r.data);

export default api;
